import pandas as pd
import json

# Carica dati dalla tabella
df = query_db("SELECT * FROM dbo.BudgetMensile_2026")
data_records = df.to_dict('records')
json_data = json.dumps(data_records, default=str)

html = """<!DOCTYPE html>
<html lang="it">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Budget Mensile 2026 - Editabile</title>
    <style>
        * { box-sizing: border-box; }
        body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; margin: 0; padding: 0; }
        .container { max-width: 1000px; margin: 0 auto; padding: 20px; }
        h1 { margin-top: 0; color: #1a365d; }
        .status-message { padding: 12px 16px; margin: 12px 0; border-radius: 6px; display: none; font-weight: 500; }
        .status-message.success { display: block; background: #c6f6d5; color: #22543d; border-left: 4px solid #48bb78; }
        .status-message.error { display: block; background: #fed7d7; color: #742a2a; border-left: 4px solid #f56565; }
        .status-message.info { display: block; background: #bee3f8; color: #2c5282; border-left: 4px solid #4299e1; }
        table { width: 100%; border-collapse: collapse; margin-top: 20px; }
        thead { background: #edf2f7; }
        th { padding: 12px; text-align: left; font-weight: 600; color: #2d3748; border-bottom: 2px solid #cbd5e0; }
        td { padding: 12px; border-bottom: 1px solid #e2e8f0; }
        tbody tr:hover { background: #f7fafc; }
        .editable-cell { cursor: text; position: relative; }
        .editable-cell:focus { outline: 2px solid #4299e1; outline-offset: -2px; background: #ebf8ff; }
        .editable-cell.modified { outline: 2px dashed #ed8936; outline-offset: -2px; background: #fffaf0; }
        .action-cell { text-align: center; }
        .btn { padding: 8px 12px; border: none; border-radius: 4px; cursor: pointer; font-weight: 500; font-size: 14px; transition: all 0.2s; }
        .btn-primary { background: #4299e1; color: white; }
        .btn-primary:hover:not(:disabled) { background: #3182ce; }
        .btn-primary:disabled { opacity: 0.6; cursor: not-allowed; }
        .btn-secondary { background: #cbd5e0; color: #2d3748; }
        .btn-secondary:hover:not(:disabled) { background: #a0aec0; }
        .btn-danger { background: #f56565; color: white; }
        .btn-danger:hover:not(:disabled) { background: #e53e3e; }
        .btn-danger:disabled { opacity: 0.6; cursor: not-allowed; }
        .btn-group { display: flex; gap: 6px; }
        .numeric { text-align: right; font-family: 'Courier New', monospace; }
    </style>
</head>
<body>
    <div class="container">
        <h1>📊 Budget Mensile 2026</h1>
        <p style="color: #718096; margin-bottom: 20px;">Tabella editabile - Modifica i valori e clicca "Salva" per aggiornare il database</p>

        <div id="statusMessage" class="status-message"></div>

        <table>
            <thead>
                <tr>
                    <th>Anno</th>
                    <th>Mese</th>
                    <th>Nome Mese</th>
                    <th class="numeric">Peso</th>
                    <th class="numeric">Budget Mensile (€)</th>
                    <th style="width: 140px;">Azioni</th>
                </tr>
            </thead>
            <tbody id="tableBody"></tbody>
        </table>
    </div>

    <script>
        window.__DB_TABLE__ = 'dbo.BudgetMensile_2026';
        window.__DB_PK__ = ['Anno', 'Mese'];

        var data = """ + json_data + """;
        var tableBody = document.getElementById('tableBody');

        data.forEach(function(row, index) {
            var tr = document.createElement('tr');
            tr.dataset.originalData = JSON.stringify(row);
            tr.dataset.rowIndex = index;

            tr.innerHTML =
                '<td class="editable-cell" contenteditable="false" data-field="Anno">' + row.Anno + '</td>' +
                '<td class="editable-cell" contenteditable="false" data-field="Mese">' + row.Mese + '</td>' +
                '<td class="editable-cell" contenteditable="true" data-field="NomeMese">' + (row.NomeMese || '-') + '</td>' +
                '<td class="editable-cell numeric" contenteditable="true" data-field="Peso">' + (row.Peso || '0') + '</td>' +
                '<td class="editable-cell numeric" contenteditable="true" data-field="BudgetMensile">' + formatNumber(row.BudgetMensile) + '</td>' +
                '<td class="action-cell"><div class="btn-group"><button class="btn btn-primary" onclick="saveRow(this)">Salva</button><button class="btn btn-danger" onclick="deleteRow(this)">Elimina</button></div></td>';

            var cells = tr.querySelectorAll('.editable-cell[contenteditable="true"]');
            cells.forEach(function(cell) {
                cell.addEventListener('input', function() { 
                    this.classList.add('modified'); 
                });
            });

            tableBody.appendChild(tr);
        });

        function formatNumber(num) {
            if (num === null || num === undefined) return '0';
            return parseFloat(num).toLocaleString('it-IT', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
        }

        function parseNumber(str) {
            if (!str) return 0;
            return parseFloat(str.replace(/\./g, '').replace(',', '.')) || 0;
        }

        function saveRow(button) {
            var tr = button.closest('tr');
            var rowData = JSON.parse(tr.dataset.originalData);
            var hasChanges = false;

            tr.querySelectorAll('.editable-cell[contenteditable="true"]').forEach(function(cell) {
                var field = cell.dataset.field;
                var newValue = cell.textContent.trim();

                if (field === 'Peso' || field === 'BudgetMensile') {
                    newValue = parseNumber(newValue);
                }

                if (rowData[field] != newValue) {
                    hasChanges = true;
                }
                rowData[field] = newValue;
            });

            if (!hasChanges) {
                showStatus('Nessuna modifica rilevata', 'info');
                return;
            }

            button.disabled = true;
            button.textContent = 'Salvataggio...';

            saveToDb('dbo.BudgetMensile_2026', rowData, ['Anno', 'Mese'])
                .then(function(r) {
                    if (r.success) {
                        showStatus('✅ Riga salvata con successo!', 'success');
                        tr.dataset.originalData = JSON.stringify(rowData);
                        tr.querySelectorAll('.editable-cell').forEach(function(c) { 
                            c.classList.remove('modified'); 
                        });
                        // Riformatta i numeri dopo il salvataggio
                        tr.querySelectorAll('.editable-cell.numeric').forEach(function(c) {
                            if (c.dataset.field === 'BudgetMensile') {
                                c.textContent = formatNumber(parseNumber(c.textContent));
                            }
                        });
                    } else { 
                        showStatus('❌ Errore: ' + r.message, 'error'); 
                    }
                })
                .catch(function(e) { 
                    showStatus('❌ Errore: ' + e.message, 'error'); 
                })
                .finally(function() { 
                    button.disabled = false; 
                    button.textContent = 'Salva'; 
                });
        }

        function deleteRow(button) {
            if (!confirm('Sei sicuro di voler eliminare questa riga? Questa azione non può essere annullata.')) {
                return;
            }

            var tr = button.closest('tr');
            var rowData = JSON.parse(tr.dataset.originalData);

            button.disabled = true;
            button.textContent = 'Eliminazione...';

            deleteFromDb('dbo.BudgetMensile_2026', rowData, ['Anno', 'Mese'])
                .then(function(r) {
                    if (r.success) {
                        tr.style.opacity = '0.5';
                        setTimeout(function() {
                            tr.remove();
                            showStatus('✅ Riga eliminata con successo!', 'success');
                        }, 300);
                    } else { 
                        showStatus('❌ Errore: ' + r.message, 'error'); 
                        button.disabled = false;
                        button.textContent = 'Elimina';
                    }
                })
                .catch(function(e) { 
                    showStatus('❌ Errore: ' + e.message, 'error'); 
                    button.disabled = false;
                    button.textContent = 'Elimina';
                });
        }

        function showStatus(msg, type) {
            var el = document.getElementById('statusMessage');
            el.textContent = msg;
            el.className = 'status-message ' + type;
            setTimeout(function() { 
                el.className = 'status-message'; 
            }, 5000);
        }
    </script>
</body>
</html>"""

result = html
